class TextEditor {
public:
    TextEditor() {
        text = "";
        cursor = 0;
    }

    void addText(string text) {
        this->text += text;
        cursor += text.size();
    }

    int deleteText(int k) {
        k = min(k, cursor);
        cursor -= k;
        return k;
    }

    string cursorLeft(int k) {
        k = min(k, cursor);
        cursor -= k;
        return text.substr(cursor, min(10, cursor));
    }

    string cursorRight(int k) {
        k = min(k, text.size() - cursor);
        cursor += k;
        return text.substr(cursor - k, min(10, k));
    }
private:
    string text;
    int cursor;
};
```
